import{_ as a,o,c as l,a0 as i}from"./chunks/framework.BFy5Ffxw.js";const u=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),d={name:"changelog.md"};function t(c,e,n,r,s,h){return o(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to cymbal are documented here.</p><h2 id="_0-3-0-2026-03-24" tabindex="-1">[0.3.0] - 2026-03-24 <a class="header-anchor" href="#_0-3-0-2026-03-24" aria-label="Permalink to &quot;[0.3.0] - 2026-03-24&quot;">​</a></h2><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Per-repo databases</strong> — each repo gets its own SQLite DB at <code>~/.cymbal/repos/&lt;hash&gt;/index.db</code>, eliminating cross-repo symbol bleed. Searching in repo A no longer returns results from repo B.</li><li>Removed <code>repos</code> table and <code>repo_id</code> column — no longer needed since each DB is one repo</li><li>Added <code>meta</code> table storing <code>repo_root</code> path per database</li><li><code>cymbal ls --repos</code> lists all indexed repos with file/symbol counts</li><li><code>--repo</code> flag removed (repo identity comes from DB path now)</li><li><code>--db</code> flag still works as override for all commands</li></ul><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>refs</code> and <code>impact</code> now show surrounding call-site context (1 line above/below by default, adjustable with <code>-C</code>)</li><li>VitePress docs site at chain.sh/cymbal with chain.sh design language</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Stale symbol entries from moved/deleted repos no longer pollute search results</li></ul><h2 id="_0-2-0-2026-03-23" tabindex="-1">[0.2.0] - 2026-03-23 <a class="header-anchor" href="#_0-2-0-2026-03-23" aria-label="Permalink to &quot;[0.2.0] - 2026-03-23&quot;">​</a></h2><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>All commands now output agent-native frontmatter+content format by default (YAML metadata + content body, optimized for LLM token efficiency)</li><li><code>refs</code> and <code>impact</code> deduplicate identical call sites — grouped by file with site count</li><li><code>context</code> callers section uses the same dedup</li><li><code>search</code> results ranked by relevance: exact name match first, then prefix, then contains</li><li>Default limits lowered: refs 50→20, impact 100→50, search 50→20</li><li><code>refs</code>, <code>impact</code>, and <code>context</code> now show actual source lines at call sites, not just line numbers</li></ul><h2 id="_0-1-0-2026-03-23" tabindex="-1">[0.1.0] - 2026-03-23 <a class="header-anchor" href="#_0-1-0-2026-03-23" aria-label="Permalink to &quot;[0.1.0] - 2026-03-23&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Core indexing engine with tree-sitter parsing, SQLite FTS5 storage, and AI summaries via oneagent</li><li>Batched summarization with diff tracking and model selection</li><li><code>cymbal index</code> — index a codebase</li><li><code>cymbal ls</code> — list files and repo stats</li><li><code>cymbal outline</code> — show file structure</li><li><code>cymbal search</code> — symbol and text search</li><li><code>cymbal show</code> — display symbol source</li><li><code>cymbal refs</code> — find references to a symbol</li><li><code>cymbal importers</code> — reverse import lookup</li><li><code>cymbal impact</code> — transitive caller analysis</li><li><code>cymbal diff</code> — git diff scoped to a symbol</li><li><code>cymbal context</code> — bundled source, callers, and imports in one call</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Overlapping sub-repo detection prevents duplicate symbol indexing</li></ul>',17)])])}const b=a(d,[["render",t]]);export{u as __pageData,b as default};
